// n8n envolve o payload do webhook em { headers, params, query, body }
// então $input.first().json.body é o payload real da Evolution API
const raw  = $input.first().json;
const body = raw.body ?? raw; // fallback para chamadas diretas

const remoteJid =
  body?.data?.key?.remoteJid ||
  body?.key?.remoteJid || '';

// Ignorar mensagens de grupos
if (remoteJid.includes('@g.us')) return [];

const phone = remoteJid
  .replace('@s.whatsapp.net', '')
  .replace('@c.us', '')
  .trim();

if (!phone) return [];

// Ignorar mensagens enviadas pelo próprio bot
const fromMe = body?.data?.key?.fromMe ?? body?.key?.fromMe ?? false;
if (fromMe) return [];

// Extrair texto (múltiplos tipos de mensagem)
const msgObj = body?.data?.message || body?.message || {};
const message = (
  msgObj?.conversation ||
  msgObj?.extendedTextMessage?.text ||
  msgObj?.imageMessage?.caption ||
  msgObj?.videoMessage?.caption ||
  msgObj?.listResponseMessage?.singleSelectReply?.selectedRowId ||
  msgObj?.buttonsResponseMessage?.selectedButtonId ||
  ''
).trim();

if (!message) return [];

return [{ json: { phone, message, rawBody: body } }];

const extracted  = $('Extrair Dados Brutos').first().json;
const phone      = extracted.phone;
const message    = extracted.message;

// ── Sessão ──────────────────────────────────────────────────
const sessionRaw = $('Redis GET Sessão').first().json?.value;
let session = {};
try { session = sessionRaw ? JSON.parse(sessionRaw) : {}; } catch {}

const defaults = {
  state: 'INICIO',
  cliente_arroba: '',
  concorrentes: '',
  nicho: '',
  followers: 0,
  taxa_engajamento_cliente: '0.00',
  taxa_engajamento_concorrente: '',
  gap_principal: '',
  oportunidade_principal: '',
  erro_critico: '',
  msg_espera_1: '',
  msg_espera_2: '',
  prova_social: '',
  link_pagamento: '',
  pdf_url: '',
};
const fullSession = { ...defaults, ...session };

// ── Histórico ────────────────────────────────────────────────
const historyRaw = $('Redis LRANGE Histórico').first().json?.value ?? [];
const history = (Array.isArray(historyRaw) ? historyRaw : [])
  .map(h => { try { return JSON.parse(h); } catch { return null; } })
  .filter(Boolean);

// Últimas 10 trocas (20 mensagens) para contexto da IA
const historyForAI = history.slice(-20).map(h => ({
  role: h.role,
  content: h.content,
}));

return [{ json: { phone, message, history, historyForAI, ...fullSession } }];

const ctx        = $('Montar Contexto Completo').first().json;
const apifyData  = $('HANDLE HTTP Apify Instagram').first().json;
const nichoRaw   = $('HANDLE HTTP OpenAI Detectar Nicho').first().json;

const profile  = Array.isArray(apifyData) ? apifyData[0] : apifyData;
const nicho    = (nichoRaw?.choices?.[0]?.message?.content ?? 'negócio').trim().toLowerCase();

const followers    = profile?.followersCount ?? 1000;
const posts        = profile?.latestPosts ?? [];
const avgLikes     = posts.length ? Math.round(posts.reduce((s,p) => s+(p.likesCount||0),0)/posts.length) : 0;
const avgComments  = posts.length ? Math.round(posts.reduce((s,p) => s+(p.commentsCount||0),0)/posts.length) : 0;
const taxa         = followers > 0 ? (((avgLikes+avgComments)/followers)*100).toFixed(2) : '0.00';

const handle = ctx.message.replace('@','').replace(/.*instagram\.com\//,'').split('/')[0].split('?')[0].trim();

return [{ json: {
  ...ctx,
  cliente_arroba: handle,
  nicho,
  followers,
  taxa_engajamento_cliente: taxa,
  profileBio: profile?.biography ?? '',
} }];

// Passa os dados adiante enriquecidos com os concorrentes
const ctx = $input.first().json;
return [{ json: { ...ctx, concorrentes: ctx.message } }];

const ctx         = $('CONC Code Salvar Concorrentes').first().json;
const deepseekRaw = $('CONC HTTP DeepSeek Análise').first().json;
const gptRaw      = $('CONC HTTP GPT4o Mensagens Espera').first().json;

let analysis = {};
let msgs = {};
try { analysis = JSON.parse(deepseekRaw.choices[0].message.content); } catch {}
try { msgs     = JSON.parse(gptRaw.choices[0].message.content); } catch {}

console.log('[DeepSeek raciocinio]', analysis.raciocinio);

return [{ json: {
  ...ctx,
  taxa_engajamento_concorrente: analysis.taxa_concorrente ?? '',
  gap_principal:                analysis.gap_principal    ?? '',
  oportunidade_principal:       analysis.oportunidade_principal ?? '',
  erro_critico:                 analysis.erro_critico     ?? '',
  msg_espera_1:                 msgs.msg_espera_1         ?? '',
  msg_espera_2:                 msgs.msg_espera_2         ?? '',
  prova_social:                 msgs.prova_social         ?? '',
} }];

