const ctx = $('Montar Contexto Completo').first().json;
const stripeSession = $('PAG HTTP Stripe Criar Checkout').first().json;
const checkoutUrl = stripeSession.url || process.env.CHECKOUT_URL_FALLBACK || 'https://pay.exemplo.com/auditoria';
return [{ json: { ...ctx, link_pagamento: checkoutUrl } }];

const body = $input.first().json;

// Stripe envia o evento como JSON
const event = body;
if (event.type !== 'checkout.session.completed') return [];

const session = event.data?.object ?? {};
const phone   = session.metadata?.phone ?? '';
const handle  = session.metadata?.handle ?? '';

if (!phone) return [];

return [{ json: { phone, handle, stripeSessionId: session.id } }];

const stripe = $('STRIPE Code Extrair Phone').first().json;
const sessionRaw = $('STRIPE Redis GET Sessão').first().json?.value;
let session = {};
try { session = JSON.parse(sessionRaw); } catch {}

return [{ json: { ...stripe, ...session, phone: stripe.phone } }];

const ctx    = $('STRIPE Code Montar Dados PDF').first().json;
const pdfRes = $('STRIPE HTTP Gerar PDF').first().json;
return [{ json: { ...ctx, pdf_url: pdfRes.pdf_url ?? '' } }];
